export function processOrder(order, db) {
  if (!order.id) throw new Error('missing id');
  if (!order.items || order.items.length === 0) throw new Error('empty');
  if (order.total < 0) throw new Error('negative total');
  let subtotal = 0;
  for (const item of order.items) {
    subtotal += item.price * item.qty;
  }
  const tax = subtotal * 0.2;
  const shipping = subtotal > 100 ? 0 : 5;
  const total = subtotal + tax + shipping;
  db.save({ id: order.id, subtotal, tax, shipping, total });
  db.log('order.processed', order.id);
  return { id: order.id, total };
}

export function renderReport(data) {
  const headerLines = [];
  headerLines.push('# ' + data.title);
  headerLines.push('generated: ' + data.date);
  headerLines.push('author: ' + data.author);
  const bodyLines = [];
  for (const section of data.sections) {
    bodyLines.push('## ' + section.name);
    bodyLines.push(section.text);
  }
  const footerLines = [];
  footerLines.push('---');
  footerLines.push('total sections: ' + data.sections.length);
  footerLines.push('status: ' + (data.ok ? 'ok' : 'fail'));
  return headerLines.join('\n') + '\n' + bodyLines.join('\n') + '\n' + footerLines.join('\n');
}

export function setupServer(config) {
  const app = createApp();
  app.set('port', config.port || 3000);
  app.set('host', config.host || 'localhost');
  app.use(logger(config.logLevel || 'info'));
  app.use(bodyParser());
  app.use(cors(config.origins || []));
  app.get('/health', (req, res) => res.send('ok'));
  app.get('/version', (req, res) => res.send(config.version));
  app.post('/data', (req, res) => res.json(req.body));
  const conn = connect(config.dbUrl);
  conn.on('error', (e) => app.emit('db-error', e));
  conn.on('ready', () => app.emit('db-ready'));
  return { app, conn };
}

export function classifyToken(ch, ctx) {
  if (ch >= '0' && ch <= '9') {
    ctx.kind = 'digit';
    return ctx.kind;
  }
  if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')) {
    ctx.kind = 'alpha';
    return ctx.kind;
  }
  if (ch === ' ' || ch === '\t' || ch === '\n') {
    ctx.kind = 'space';
    return ctx.kind;
  }
  if (ch === '+' || ch === '-' || ch === '*' || ch === '/') {
    ctx.kind = 'operator';
    return ctx.kind;
  }
  ctx.kind = 'symbol';
  return ctx.kind;
}

export function validateForm(form, errors) {
  if (!form.name) errors.push('name required');
  if (form.name && form.name.length > 50) errors.push('name too long');
  if (!form.email) errors.push('email required');
  if (form.email && !form.email.includes('@')) errors.push('email invalid');
  if (!form.age) errors.push('age required');
  if (form.age && form.age < 0) errors.push('age negative');
  if (form.age && form.age > 150) errors.push('age too large');
  if (!form.country) errors.push('country required');
  if (form.password && form.password.length < 8) errors.push('password short');
  if (form.password !== form.confirm) errors.push('password mismatch');
  return errors.length === 0;
}

export function buildQuery(opts) {
  let sql = 'SELECT ';
  sql += opts.columns ? opts.columns.join(', ') : '*';
  sql += ' FROM ' + opts.table;
  if (opts.where) {
    const clauses = [];
    for (const key of Object.keys(opts.where)) {
      clauses.push(key + ' = ' + JSON.stringify(opts.where[key]));
    }
    sql += ' WHERE ' + clauses.join(' AND ');
  }
  if (opts.orderBy) sql += ' ORDER BY ' + opts.orderBy;
  if (opts.limit) sql += ' LIMIT ' + opts.limit;
  return sql;
}

export function dispatchEvent(event, handlers) {
  if (event.type === 'click') {
    handlers.onClick && handlers.onClick(event);
    return 'click';
  }
  if (event.type === 'hover') {
    handlers.onHover && handlers.onHover(event);
    return 'hover';
  }
  if (event.type === 'key') {
    handlers.onKey && handlers.onKey(event);
    return 'key';
  }
  handlers.onDefault && handlers.onDefault(event);
  return 'default';
}

export function normalizeConfig(raw) {
  const config = {};
  config.host = raw.host || 'localhost';
  config.port = raw.port || 8080;
  config.timeout = raw.timeout || 30000;
  config.retries = raw.retries || 3;
  config.verbose = raw.verbose === true;
  config.headers = raw.headers || {};
  config.auth = raw.auth ? { user: raw.auth.user, pass: raw.auth.pass } : null;
  config.proxy = raw.proxy || null;
  config.tags = Array.isArray(raw.tags) ? raw.tags : [];
  return config;
}

export function summarize(records) {
  let total = 0;
  let max = -Infinity;
  let min = Infinity;
  const byType = {};
  for (const r of records) {
    total += r.value;
    if (r.value > max) max = r.value;
    if (r.value < min) min = r.value;
    byType[r.type] = (byType[r.type] || 0) + 1;
  }
  const avg = records.length ? total / records.length : 0;
  return { total, max, min, avg, byType, count: records.length };
}

export function transformUser(user) {
  const out = {};
  out.id = String(user.id);
  out.name = (user.firstName + ' ' + user.lastName).trim();
  out.email = user.email ? user.email.toLowerCase() : null;
  out.active = user.status === 'active';
  out.roles = user.roles ? user.roles.map((r) => r.name) : [];
  out.createdAt = new Date(user.created).toISOString();
  out.avatar = user.avatar || '/default.png';
  out.locale = user.locale || 'en-US';
  return out;
}
